module edge_detector(
    input clk,
    input reset,
    input signal,
    output reg edge_detected
);

    reg signal_delayed;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset) begin
            signal_delayed <= 0;
            edge_detected <= 0;
        end else begin
            edge_detected <= signal & ~signal_delayed;
            signal_delayed <= signal;
        end
    end

endmodule
